// Parse and normalize incoming client data
const body = $input.first().json.body || $input.first().json;

const clientName = body.name || body.customer_name || body.full_name || 'Valued Client';
const firstName = clientName.split(' ')[0];
const clientEmail = body.email || body.customer_email;
const company = body.company || body.company_name || '';
const plan = body.plan || body.product || 'Starter';
const clientId = 'CL_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6).toUpperCase();

if (!clientEmail) throw new Error('Missing required field: email');

const now = new Date();
const day1 = new Date(now); day1.setDate(now.getDate() + 1);
const day3 = new Date(now); day3.setDate(now.getDate() + 3);
const day7 = new Date(now); day7.setDate(now.getDate() + 7);
const day14 = new Date(now); day14.setDate(now.getDate() + 14);

return [{
  json: {
    client_id: clientId,
    client_name: clientName,
    first_name: firstName,
    client_email: clientEmail,
    company: company,
    plan: plan,
    signup_date: now.toISOString(),
    day1_date: day1.toISOString(),
    day3_date: day3.toISOString(),
    day7_date: day7.toISOString(),
    day14_date: day14.toISOString(),
    dashboard_url: `REPLACE_WITH_DASHBOARD_URL`,
    calendly_url: `REPLACE_WITH_CALENDLY_URL`
  }
}];

const error = $input.first().json;
console.error('ME-09 Error:', JSON.stringify(error));
return [{ json: { error: true, message: error.message || 'Drip sequence error', timestamp: new Date().toISOString() } }];
